    geom_segment(aes(y = l, yend = h), linewidth = 2, alpha = 0.5) +
    scale_color_manual(values = c("95% positive" = "darkblue", "80% positive" = "blue", "neutral" = "grey", "80% negative" = "red", "95% negative" = "darkred")) +
